tes":"Comissão referente à OS #OS1756574770389","legacy_parent_transaction_id":"","legacy_bank_account_id":"","legacy_parent_recurrence_id":"","is_installment":"","recurrence_end_date":"","installment_count":"","status":"pendente","created_at":"2025-08-30T17:46:00.449000","updated_at":"2025-08-30T17:46:00.449000","created_by":"beenkoficial@gmail.com"},{"legacy_financial_transaction_id":"68b338d759c6136ec67a5677","legacy_installment_id":"","type":"entrada","current_installment":"","legacy_employee_financial_record_id":"","category":"servicos","amount":"295","due_date":"2025-08-30","description":"Recebimento OS #OS1756574770389 (Parcelado)","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento da Ordem de Serviço #OS1756574770389 - pix - 3x","legacy_parent_transaction_id":"","legacy_bank_account_id":"","legacy_parent_recurrence_id":"","is_installment":"","recurrence_end_date":"","installment_count":"","status":"parcial","created_at":"2025-08-30T17:45:59.652000","updated_at":"2025-08-30T17:45:59.652000","created_by":"beenkoficial@gmail.com"},{"legacy_financial_transaction_id":"68b32e60569afbe8e98a5a3a","legacy_installment_id":"","type":"saida","current_installment":"","legacy_employee_financial_record_id":"","category":"salarios","amount":"59","due_date":"2025-08-30","description":"Comissão Afonso Santos - OS #OS1756570283780","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Comissão referente à OS #OS1756570283780","legacy_parent_transaction_id":"","legacy_bank_account_id":"","legacy_parent_recurrence_id":"","is_installment":"","recurrence_end_date":"","installment_count":"","status":"pago","created_at":"2025-08-30T17:01:20.157000","updated_at":"2025-08-30T17:42:13.367000","created_by":"beenkoficial@gmail.com"},{"legacy_financial_transaction_id":"68b32e5f0fd91c51d4744ea3","legacy_installment_id":"","type":"entrada","current_installment":"","legacy_employee_financial_record_id":"","category":"servicos","amount":"295","due_date":"2025-08-30","description":"Recebimento OS #OS1756570283780 (Parcelado)","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento da Ordem de Serviço #OS1756570283780 - pix - 2x","legacy_parent_transaction_id":"","legacy_bank_account_id":"","legacy_parent_recurrence_id":"","is_installment":"","recurrence_end_date":"","installment_count":"","status":"parcial","created_at":"2025-08-30T17:01:19.885000","updated_at":"2025-08-30T17:01:19.885000","created_by":"beenkoficial@gmail.com"},{"legacy_financial_transaction_id":"68b3279bc7ca560761932b39","legacy_installment_id":"","type":"saida","current_installment":"","legacy_employee_financial_record_id":"","category":"salarios","amount":"360","due_date":"2025-08-30","description":"Comissão Afonso Santos - OS #OS1756570965978","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Comissão referente à OS #OS1756570965978","legacy_parent_transaction_id":"","legacy_bank_account_id":"","legacy_parent_recurrence_id":"","is_installment":"","recurrence_end_date":"","installment_count":"","status":"pago","created_at":"2025-08-30T16:32:27.107000","updated_at":"2025-08-30T17:44:27.226000","created_by":"beenkoficial@gmail.com"},{"legacy_financial_transaction_id":"68b3279a90462226c114c838","legacy_installment_id":"","type":"entrada","current_installment":"","legacy_employee_financial_record_id":"","category":"servicos","amount":"1800","due_date":"2025-08-30","description":"Recebimento OS #OS1756570965978","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento da Ordem de Serviço #OS1756570965978 - dinheiro","legacy_parent_transaction_id":"","legacy_bank_account_id":"","legacy_parent_recurrence_id":"","is_installment":"","recurrence_end_date":"","installment_count":"","status":"pago","created_at":"2025-08-30T16:32:26.825000","updated_at":"2025-08-30T16:32:26.825000","created_by":"beenkoficial@gmail.com"}]$financial_transactions$::jsonb) AS src(
    legacy_financial_transaction_id text,
    legacy_installment_id text,
    type text,
    current_installment text,
    legacy_employee_financial_record_id text,
    category text,
    amount text,
    due_date text,
    description text,
    recurrence text,
    legacy_purchase_id text,
    notes text,
    legacy_parent_transaction_id text,
    legacy_bank_account_id text,
    legacy_parent_recurrence_id text,
    is_installment text,
    recurrence_end_date text,
    installment_count text,
    status text,
    created_at text,
    updated_at text,
    created_by text
  );

  CREATE TEMP TABLE tmp_skipped_financial_transaction_resolved AS
  SELECT
    src.*,
    COALESCE(
      recurrence_parent.organization_id,
      transaction_parent.organization_id,
      installments.organization_id,
      employee_records.organization_id,
      bank_accounts.organization_id,
      purchases.organization_id
    ) AS organization_id,
    employee_records.id AS employee_financial_record_id,
    bank_accounts.id AS bank_account_id,
    installments.id AS service_order_installment_id,
    purchases.id AS purchase_id,
    COALESCE(installments.service_order_id, employee_records.service_order_id) AS service_order_id
  FROM tmp_skipped_financial_transaction_source AS src
  LEFT JOIN public.financial_transactions AS recurrence_parent
    ON recurrence_parent.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_parent_recurrence_id)
  LEFT JOIN public.financial_transactions AS transaction_parent
    ON transaction_parent.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_parent_transaction_id)
  LEFT JOIN public.service_order_installments AS installments
    ON installments.id = uuid_generate_v5(v_namespace, 'service_order_installment:' || src.legacy_installment_id)
  LEFT JOIN public.employee_financial_records AS employee_records
    ON employee_records.id = uuid_generate_v5(v_namespace, 'employee_financial_record:' || src.legacy_employee_financial_record_id)
  LEFT JOIN public.bank_accounts AS bank_accounts
    ON bank_accounts.id = uuid_generate_v5(v_namespace, 'bank_account:' || src.legacy_bank_account_id)
  LEFT JOIN public.purchases AS purchases
    ON purchases.id = uuid_generate_v5(v_namespace, 'purchase:' || src.legacy_purchase_id);

  INSERT INTO public.financial_transactions (
    id,
    organization_id,
    description,
    amount,
    due_date,
    type,
    status,
    category,
    recurrence,
    recurrence_end_date,
    parent_recurrence_id,
    is_installment,
    installment_count,
    current_installment,
    parent_transaction_id,
    employee_financial_record_id,
    bank_account_id,
    service_order_installment_id,
    purchase_id,
    service_order_id,
    payment_method,
    notes,
    created_at,
    created_by,
    updated_at,
    updated_by,
    deleted_at,
    deleted_by
  )
  SELECT
    uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id),
    src.organization_id,
    LEFT(COALESCE(NULLIF(src.description, ''), 'Lancamento financeiro'), 300),
    COALESCE(NULLIF(src.amount, '')::numeric, 0),
    COALESCE(NULLIF(src.due_date, '')::date, NULLIF(src.created_at, '')::date, CURRENT_DATE),
    CASE src.type
      WHEN 'entrada' THEN 'income'
      WHEN 'saida' THEN 'expense'
      WHEN 'transferencia_entrada' THEN 'transfer_in'
      WHEN 'transferencia_saida' THEN 'transfer_out'
      ELSE 'expense'
    END,
    CASE src.status WHEN 'pago' THEN 'paid' WHEN 'cancelado' THEN 'cancelled' ELSE 'pending' END,
    LEFT(COALESCE(NULLIF(BTRIM(src.category), ''), 'outros'), 100),
    CASE src.recurrence WHEN 'nao_recorrente' THEN 'non_recurring' WHEN 'mensal' THEN 'monthly' WHEN 'anual' THEN 'annual' ELSE NULL END,
    NULLIF(src.recurrence_end_date, '')::date,
    NULL,
    COALESCE(NULLIF(src.is_installment, '')::boolean, false),
    NULLIF(src.installment_count, '')::int,
    NULLIF(src.current_installment, '')::int,
    NULL,
    src.employee_financial_record_id,
    src.bank_account_id,
    src.service_order_installment_id,
    src.purchase_id,
    src.service_order_id,
    NULL,
    NULLIF(src.notes, ''),
    COALESCE(NULLIF(src.created_at, '')::timestamptz, now()),
    NULLIF(src.created_by, ''),
    COALESCE(NULLIF(src.updated_at, '')::timestamptz, NULLIF(src.created_at, '')::timestamptz, now()),
    NULLIF(src.created_by, ''),
    NULL,
    NULL
  FROM tmp_skipped_financial_transaction_resolved AS src
  WHERE src.organization_id IS NOT NULL
    AND COALESCE(src.legacy_financial_transaction_id, '') <> ''
    AND COALESCE(src.description, '') <> ''
    AND COALESCE(src.amount, '') <> ''
    AND COALESCE(src.due_date, '') <> ''
  ON CONFLICT (id) DO UPDATE
  SET
    organization_id = EXCLUDED.organization_id,
    description = EXCLUDED.description,
    amount = EXCLUDED.amount,
    due_date = EXCLUDED.due_date,
    type = EXCLUDED.type,
    status = EXCLUDED.status,
    category = EXCLUDED.category,
    recurrence = EXCLUDED.recurrence,
    recurrence_end_date = EXCLUDED.recurrence_end_date,
    is_installment = EXCLUDED.is_installment,
    installment_count = EXCLUDED.installment_count,
    current_installment = EXCLUDED.current_installment,
    employee_financial_record_id = EXCLUDED.employee_financial_record_id,
    bank_account_id = EXCLUDED.bank_account_id,
    service_order_installment_id = EXCLUDED.service_order_installment_id,
    purchase_id = EXCLUDED.purchase_id,
    service_order_id = EXCLUDED.service_order_id,
    payment_method = EXCLUDED.payment_method,
    notes = EXCLUDED.notes,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;

  GET DIAGNOSTICS v_inserted_count = ROW_COUNT;

  UPDATE public.financial_transactions AS ft
  SET parent_recurrence_id = parent_ft.id
  FROM tmp_skipped_financial_transaction_resolved AS src
  JOIN public.financial_transactions AS parent_ft
    ON parent_ft.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_parent_recurrence_id)
  WHERE ft.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
    AND COALESCE(src.legacy_parent_recurrence_id, '') <> '';

  UPDATE public.financial_transactions AS ft
  SET parent_transaction_id = parent_ft.id
  FROM tmp_skipped_financial_transaction_resolved AS src
  JOIN public.financial_transactions AS parent_ft
    ON parent_ft.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_parent_transaction_id)
  WHERE ft.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
    AND COALESCE(src.legacy_parent_transaction_id, '') <> '';

  UPDATE public.service_order_installments AS installments
  SET financial_transaction_id = financial_transactions.id
  FROM tmp_skipped_financial_transaction_resolved AS src
  JOIN public.financial_transactions AS financial_transactions
    ON financial_transactions.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
  WHERE installments.id = uuid_generate_v5(v_namespace, 'service_order_installment:' || src.legacy_installment_id)
    AND COALESCE(src.legacy_installment_id, '') <> '';

  UPDATE public.employee_financial_records AS records
  SET financial_transaction_id = financial_transactions.id
  FROM tmp_skipped_financial_transaction_resolved AS src
  JOIN public.financial_transactions AS financial_transactions
    ON financial_transactions.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
  WHERE records.id = uuid_generate_v5(v_namespace, 'employee_financial_record:' || src.legacy_employee_financial_record_id)
    AND COALESCE(src.legacy_employee_financial_record_id, '') <> '';

  SELECT count(*)
  INTO v_unresolved_count
  FROM tmp_skipped_financial_transaction_resolved AS src
  WHERE src.organization_id IS NULL;

  RAISE NOTICE 'Skipped financial transaction recovery complete: % inserted/updated, % unresolved.',
    v_inserted_count,
    v_unresolved_count;
END $$;
